mapper.select:
select f.shop_id, f.flower_id, f.flower_name, f.price, f.main_image, fi.stock_quantity as stock, fi.sold_quantity as sold, f.status from flowers f join flowers_inventory fi on f.flower_id = fi.flower_id
f.shop_id = #{shopId}
AND f.category_id = #{categoryId}
AND f.status = 1
ORDER BY f.updated_at DESC
